  def generate
    query = params[:query]

    if query.blank?
      redirect_to reports_path, alert: "SQL query cannot be empty."
      return
    end

    begin
      # Use ActiveRecord::Base.connection.execute to run the raw SQL
      # This is highly flexible but also highly dangerous if not properly secured
      # Ensure this controller is only accessible by trusted power users/admins
      results = ActiveRecord::Base.connection.execute(query)

      # For SELECT queries, the results object might be an array of hashes or similar
      # depending on the database adapter. For a simple display, we'll convert to an array of arrays
      # if it's a PG::Result or similar.
      @headers = results.fields if results.respond_to?(:fields) # For PostgreSQL results
      @rows = results.to_a if results.respond_to?(:to_a) # For PostgreSQL results

      # If it's not a SELECT query (e.g., INSERT, UPDATE, DELETE), results might be nil or a count
      unless @headers || @rows
        @message = "Query executed successfully. Affected rows: #{results}"
      end

    rescue ActiveRecord::StatementInvalid => e
      redirect_to reports_path, alert: "SQL Error: #{e.message}"
    rescue => e
      redirect_to reports_path, alert: "An unexpected error occurred: #{e.message}"
    end
